from typing import List, Dict, Any, Optional, Callable
from leann.api import SearchResult
from leann.metadata_filter import MetadataFilterEngine  # imported but not used, kept for API compatibility
from collections import defaultdict


def aggregate_search_results(
    search_results: List[SearchResult],
    group_by_field: str,
    aggregation_funcs: Optional[Dict[str, Callable]] = None
) -> Dict[str, Dict[str, Any]]:
    """Aggregate search results by a metadata field with optional statistics.

    Args:
        search_results: List of SearchResult objects to aggregate.
        group_by_field: Metadata field name to group by (taken from result.metadata).
        aggregation_funcs: Optional dict mapping statistic_name -> aggregation function.
            - If None, defaults to:
                {
                    "count": len,
                    "avg_score": lambda scores: sum(scores) / len(scores) if scores else 0.0,
                    "max_score": max,
                    "min_score": min,
                }
            - Each aggregation function will be called with a list of scores for that group.
              The result will be stored under its corresponding key in the stats dict.

    Returns:
        Dictionary mapping group_value (as string) to aggregated statistics dict.
        Example (using defaults):
            {
                "tech": {
                    "count": 5,
                    "avg_score": 0.85,
                    "max_score": 0.95,
                    "min_score": 0.7,
                },
                "unknown": {
                    "count": 2,
                    "avg_score": 0.6,
                    "max_score": 0.6,
                    "min_score": 0.6,
                }
            }
    """
    # Default aggregation functions operating over list of scores
    if aggregation_funcs is None:
        def _safe_avg(values):
            return sum(values) / len(values) if values else 0.0

        aggregation_funcs = {
            "count": len,
            "avg_score": _safe_avg,
            "max_score": max,
            "min_score": min,
        }

    # Group scores by group value
    grouped_scores: Dict[str, List[float]] = defaultdict(list)

    for result in search_results:
        # Defensive access to metadata & score
        metadata = getattr(result, "metadata", {}) or {}
        # Handle missing grouping field -> 'unknown'
        group_value = metadata.get(group_by_field, "unknown")
        if group_value is None or group_value == "":
            group_value = "unknown"
        # Normalize group_value to string for dict key stability
        group_key = str(group_value)

        score = getattr(result, "score", None)
        # Only aggregate results that have a numeric score
        if isinstance(score, (int, float)):
            grouped_scores[group_key].append(float(score))

    aggregated: Dict[str, Dict[str, Any]] = {}

    for group_key, scores in grouped_scores.items():
        stats: Dict[str, Any] = {}
        for stat_name, func in aggregation_funcs.items():
            # Each function receives the list of scores for that group
            stats[stat_name] = func(scores)
        aggregated[group_key] = stats

    # Also ensure that if some group exists only with non-numeric scores,
    # it still appears with empty statistics (all aggregations run on empty list).
    # This requires a second pass over results to capture any missing groups.
    seen_groups = set(grouped_scores.keys())
    for result in search_results:
        metadata = getattr(result, "metadata", {}) or {}
        group_value = metadata.get(group_by_field, "unknown")
        if group_value is None or group_value == "":
            group_value = "unknown"
        group_key = str(group_value)
        if group_key not in seen_groups:
            # No numeric scores collected; run aggregations on empty list
            scores: List[float] = []
            stats: Dict[str, Any] = {}
            for stat_name, func in aggregation_funcs.items():
                stats[stat_name] = func(scores)
            aggregated[group_key] = stats
            seen_groups.add(group_key)

    return aggregated

